import re

def to_snake_case(s):
    s = re.sub('(.)([A-Z][a-z]+)', r'\1_\2', s)
    return re.sub('([a-z0-9])([A-Z])', r'\1_\2', s).lower()

if __name__ == "__main__":
    print(f"someString -> {to_snake_case('someString')}")
